  "seedPrimitives": [
    {
      "id": "incursion",
      "kind": "primitive",
      "definition": "A bounded movement into the real operational surface to advance work and discover shape under pressure.",
      "demo_relevance": [
        "opportunity_intelligence_os",
        "fiscal_reconciliation_copilot"
      ],
      "ui_implication": "Show each run as an incursion with intent, steps, evidence, confidence changes, and stopping point."
    },
    {
      "id": "lateral_exploration",
      "kind": "primitive",
      "definition": "Unstructured or semi-structured probing used when confidence drops, before declaring a hard stop.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot",
        "opportunity_intelligence_os"
      ],
      "ui_implication": "Add an exploration lane that records probes attempted and whether they raised or lowered confidence."
    },
    {
      "id": "false_limit",
      "kind": "failure_mode",
      "definition": "A boundary produced by agent hesitation, safety conditioning, insufficient context, or premature refusal rather than an actual operational impossibility.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot"
      ],
      "ui_implication": "Distinguish stop reasons: real limit, missing evidence, reversible uncertainty, false/contextual limit, human decision required."
    },
    {
      "id": "decision_provenance",
      "kind": "invariant",
      "definition": "Every proposed action must preserve who decided, based on what evidence, after what exploration, under what confidence, with what consequence class.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot",
        "support_triage_hitl_runtime"
      ],
      "ui_implication": "Decision packet and audit trail must be first-class artifacts, not hidden logs."
    },
    {
      "id": "human_weight",
      "kind": "invariant",
      "definition": "The AI may be capable, but a person must hold responsibility for consequential decisions, especially irreversible writes.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot"
      ],
      "ui_implication": "Approval gates must name the human role and the exact decision being accepted."
    },
    {
      "id": "agent_movement",
      "kind": "invariant",
      "definition": "The path the agent took is as important as the final answer because it lets another person understand and trust or challenge the work.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot",
        "multi_lens_agent_eval_lab"
      ],
      "ui_implication": "Trace viewer should show inspections, attempts, confidence shifts, and rationale in chronological order."
    },
    {
      "id": "market_topology",
      "kind": "primitive",
      "definition": "A corpus of similar job postings reveals the shape of market demand; the totality can be extracted from many parts.",
      "demo_relevance": [
        "opportunity_intelligence_os"
      ],
      "ui_implication": "Show role clusters, demand surfaces, proof gaps, and market-vs-body-of-work alignment at a glance."
    },
    {
      "id": "body_of_work_alignment",
      "kind": "primitive",
      "definition": "Opportunities should be ranked by how they fit the user's actual strengths and proof assets, not just role keyword overlap.",
      "demo_relevance": [
        "opportunity_intelligence_os"
      ],
      "ui_implication": "Ranking board should explain fit, missing proof, and which asset/demo closes the gap."
    },
    {
      "id": "self_improvable_work_unit",
      "kind": "philosophical_spine",
      "definition": "The smallest useful artifact is a unit of actual operational work that can be replayed, inspected, and improved by better future models.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot",
        "opportunity_intelligence_os"
      ],
      "ui_implication": "Each run should export a trace, decision packet, dataset diff, and next-run learning."
    },
    {
      "id": "irreversible_action_gate",
      "kind": "safety_boundary",
      "definition": "The agent must never perform irreversible actions without explicit human authorization.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot",
        "support_triage_hitl_runtime"
      ],
      "ui_implication": "Separate read/explore/suggest permissions from write/apply permissions."
    },
    {
      "id": "operator_weight",
      "kind": "responsibility_model",
      "definition": "The operator is the human who holds the physical weight of accepting, rejecting, or redirecting the agent's proposed next movement.",
      "demo_relevance": [
        "fiscal_reconciliation_copilot",
        "opportunity_intelligence_os"
      ],
      "ui_implication": "Use operator-facing approval gates, not generic approver labels. Show exactly what the operator is being asked to own."
    },
    {
      "id": "simulated_computer_use_queue",
      "kind": "demo_mechanic",
      "definition": "A public-safe simulated browser/computer-use backend over synthetic pages, forms, accounts, and submissions that demonstrates operational movement without touching real external systems.",
      "demo_relevance": [
        "opportunity_intelligence_os"
      ],
      "ui_implication": "Provide fake job pages and forms with observe/click/type/extract/submit traces, answer packets, and stop outcomes."
    }
  ],
